{
  "name": "add-numbers-lib",
  "version": "0.1.0",
  "description": "Small TypeScript library with one function addNumbers and unit tests",
  "main": "dist/index.js",
  "types": "dist/index.d.ts",
  "scripts": {
    "build": "tsc",
    "test": "jest",
    "prepare": "npm run build"
  },
  "author": "",
  "license": "MIT",
  "devDependencies": {
    "@types/jest": "^29.5.2",
    "jest": "^29.6.1",
    "ts-jest": "^29.1.0",
    "typescript": "^5.2.2"
  }
}

export function addNumbers(a: number, b: number): number {
  // Validate inputs are finite numbers
  if (!Number.isFinite(a) || !Number.isFinite(b)) {
    throw new TypeError('addNumbers: both arguments must be finite numbers');
  }

  // Guard against unsafe integer inputs that might cause precision loss
  const max = Number.MAX_SAFE_INTEGER;
  if (Math.abs(a) > max || Math.abs(b) > max) {
    throw new RangeError('addNumbers: input magnitude exceeds Number.MAX_SAFE_INTEGER');
  }

  return a + b;
}

import { addNumbers } from '../src';

describe('addNumbers', () => {
  test('adds two positive numbers', () => {
    expect(addNumbers(2, 3)).toBe(5);
  });

  test('adds negative and positive number', () => {
    expect(addNumbers(-2, 5)).toBe(3);
  });

  test('throws on NaN input', () => {
    expect(() => addNumbers(NaN, 1)).toThrow(TypeError);
  });

  test('throws on Infinity input', () => {
    expect(() => addNumbers(Infinity, 1)).toThrow(TypeError);
  });

  test('throws when inputs exceed Number.MAX_SAFE_INTEGER', () => {
    expect(() => addNumbers(Number.MAX_SAFE_INTEGER + 1, 1)).toThrow(RangeError);
  });
});
